body.script:
(function() {
  'use strict';

  const SUPABASE_URL = 'https://okasxfvoyihovohlaypz.supabase.co';
  const SUPABASE_KEY = 'sb_publishable__JK1dgzDVfrFmMETc3z-sA_HjMiueOS';
  const TOTAL_STEPS = 4;

  const supabase = window.supabase.createClient(SUPABASE_URL, SUPABASE_KEY);
  const form = document.getElementById('wizardForm');
  const stepPills = document.querySelectorAll('.steps-bar .step-pill');
  let currentStep = 1;

  function showStep(step) {
    document.querySelectorAll('.wizard-step').forEach(el => el.classList.remove('is-active'));
    const target = document.querySelector(`.wizard-step[data-step="${step}"]`);
    if (target) target.classList.add('is-active');

    if (typeof step === 'number') {
      stepPills.forEach((p, i) => {
        p.classList.remove('active', 'done');
        if (i + 1 < step) p.classList.add('done');
        else if (i + 1 === step) p.classList.add('active');
      });
    }
    window.scrollTo({ top: 0, behavior: 'smooth' });
  }

  function validateStep(step) {
    if (step === 2) {
      const requiredFields = ['nome', 'cognome', 'email'];
      let valid = true;
      requiredFields.forEach(name => {
        const input = form.querySelector(`[name="${name}"]`);
        const errorEl = form.querySelector(`[data-error-for="${name}"]`);
        if (!input.value.trim() || (name === 'email' && !input.checkValidity())) {
          if (errorEl) errorEl.classList.add('show');
          input.style.borderColor = 'var(--salt-glow, #E59856)';
          valid = false;
        } else {
          if (errorEl) errorEl.classList.remove('show');
          input.style.borderColor = '';
        }
      });
      return valid;
    }
    if (step === 3) {
      const input = form.querySelector('[name="data_nascita"]');
      const errorEl = form.querySelector('[data-error-for="data_nascita"]');
      if (!input.value) {
        if (errorEl) errorEl.classList.add('show');
        input.style.borderColor = 'var(--salt-glow, #E59856)';
        return false;
      } else {
        if (errorEl) errorEl.classList.remove('show');
        input.style.borderColor = '';
      }
      return true;
    }
    if (step === 4) {
      const required = ['c-privacy', 'c-modello'];
      const allChecked = required.every(id => document.getElementById(id).checked);
      if (!allChecked) {
        alert('Per inviare la richiesta devi accettare entrambi i consensi obbligatori.');
        return false;
      }
      return true;
    }
    return true;
  }

  form.addEventListener('click', (e) => {
    const btn = e.target.closest('[data-action]');
    if (!btn) return;
    const action = btn.dataset.action;
    if (action === 'next') {
      if (!validateStep(currentStep)) return;
      if (currentStep < TOTAL_STEPS) { currentStep++; showStep(currentStep); }
    } else if (action === 'prev') {
      if (currentStep > 1) { currentStep--; showStep(currentStep); }
    } else if (action === 'retry') {
      currentStep = 4; showStep(4);
    }
  });

  form.addEventListener('submit', async (e) => {
    e.preventDefault();
    if (!validateStep(4)) return;

    const submitBtn = document.getElementById('btnSubmit');
    submitBtn.classList.add('btn-loading');
    submitBtn.textContent = 'Invio in corso...';

    const fd = new FormData(form);

    const datiSpecifici = {
      ora_nascita: fd.get('ora_nascita') || null,
      intenzione: (fd.get('intenzione') || '').trim() || null,
      accettato_modello_pdf: !!document.getElementById('c-modello').checked
    };

    const payload = {
      tipo_richiesta: 'croce_maya',
      nome: (fd.get('nome') || '').trim(),
      cognome: (fd.get('cognome') || '').trim(),
      email: (fd.get('email') || '').trim().toLowerCase(),
      telefono: (fd.get('telefono') || '').trim() || null,
      data_nascita: fd.get('data_nascita') || null,
      luogo_nascita: (fd.get('luogo_nascita') || '').trim() || null,
      motivazione: (fd.get('intenzione') || '').trim() || null,
      dati_specifici: datiSpecifici,
      consenso_privacy: !!document.getElementById('c-privacy').checked,
      consenso_dati_salute: true,
      consenso_disclaimer_medico: true,
      user_agent: navigator.userAgent,
      referrer: document.referrer || null,
      status: 'nuova'
    };

    try {
      const { data, error } = await supabase.rpc('invia_richiesta_pubblica', {
        p_tipo_richiesta: 'croce_maya',
        p_nome: payload.nome,
        p_cognome: payload.cognome,
        p_email: payload.email,
        p_telefono: payload.telefono,
        p_data_nascita: payload.data_nascita,
        p_luogo_nascita: payload.luogo_nascita,
        p_motivazione: payload.motivazione,
        p_dati_specifici: payload.dati_specifici,
        p_consenso_privacy: payload.consenso_privacy,
        p_consenso_dati_salute: payload.consenso_dati_salute,
        p_consenso_disclaimer_medico: payload.consenso_disclaimer_medico,
        p_user_agent: payload.user_agent,
        p_referrer: payload.referrer
      });
      if (error) throw error;
      const richiestaId = data && data.id ? data.id : null;
      showStep('success');
      if (window.dataLayer) {
        window.dataLayer.push({ event: 'croce_maya_richiesta', richiesta_id: richiestaId });
      }
    } catch (err) {
      console.error('Errore invio richiesta Croce Maya:', err);
      const errEl = document.getElementById('errorMessage');
      if (errEl && err.message) {
        errEl.textContent = err.message + ' Riprova o contattami direttamente.';
      }
      showStep('error');
    } finally {
      submitBtn.classList.remove('btn-loading');
      submitBtn.innerHTML = 'Invia la richiesta ';
    }
  });
})();
